<?php
namespace App\Http\Controllers\Api;
use App\Http\Controllers\Controller;use Illuminate\Http\Request;use App\Services\{AuthService,UserService,CategoryService,CulinaryPlaceService,ReviewService,ReservationService,NotificationService};
class CulinaryController extends Controller{public function index(CulinaryPlaceService $s){return $s->search(request()->all());} public function show(\App\Models\CulinaryPlace $culinaryPlace){$culinaryPlace->increment('view_count');return $culinaryPlace->load(['category','galleries','menus','reviews.user','reviews.images','reviews.replies']);} public function store(Request $r,CulinaryPlaceService $s){$data=$r->validate(['category_id'=>'required|exists:categories,id','name'=>'required','description'=>'nullable','address'=>'required','district'=>'required','latitude'=>'required','longitude'=>'required','phone'=>'nullable','website'=>'nullable','average_price'=>'nullable','open_time'=>'nullable','close_time'=>'nullable']);$data['owner_id']=$r->user()->id;return response()->json($s->create($data),201);} public function update(Request $r,\App\Models\CulinaryPlace $culinaryPlace){$this->authorize('update',$culinaryPlace);$culinaryPlace->update($r->all());return $culinaryPlace->refresh();} public function destroy(\App\Models\CulinaryPlace $culinaryPlace){$this->authorize('delete',$culinaryPlace);$culinaryPlace->delete();return response()->noContent();} public function verify(\App\Models\CulinaryPlace $culinaryPlace,Request $r){$culinaryPlace->update($r->validate(['verification_status'=>'required|in:approved,rejected']));return $culinaryPlace;}}
